class LayoutManager{constructor(e){this.token=e;const t=document.getElementById("modalDeleteLayout");this.deleteModal=t?new bootstrap.Modal(t):null,this.currentDeleteId=null,this.init()}init(){this.initActions(),this.initSortable(),this.initDeletion()}async sendRequest(e,t){try{const o=await fetch(e,t),n=await o.text();if(!n||""===n.trim())return void MagixToast.error("Le serveur a renvoyé une réponse vide.");try{const e=JSON.parse(n);e.status||e.success?(MagixToast.success(e.message||"Opération réussie"),setTimeout((()=>window.location.reload()),800)):MagixToast.warning(e.message||"Action refusée")}catch(e){MagixToast.error("Erreur PHP (voir console)"),console.error("Détails de l'erreur PHP :",n)}}catch(e){MagixToast.error("Erreur réseau : "+e.message)}}initActions(){document.querySelectorAll(".ajax-link").forEach((e=>{e.addEventListener("click",(t=>{t.preventDefault();const o=e.href+"&hashtoken="+encodeURIComponent(this.token);this.sendRequest(o,{method:"GET"})}))}))}initSortable(){if("undefined"==typeof Sortable)return void MagixToast.error("SortableJS n'est pas chargé !");document.querySelectorAll(".sortable-list").forEach((e=>{Sortable.create(e,{group:"shared",handle:".drag-handle",animation:200,ghostClass:"sortable-ghost",filter:".no-sort",onAdd:t=>{let o=e.querySelector(".empty-placeholder");o&&(o.style.display="none")},onEnd:e=>{const t=e.to,o=t.getAttribute("data-hook");if(e.from===e.to&&e.oldIndex===e.newIndex)return;let n=[];t.querySelectorAll("li[data-id]").forEach((e=>{n.push("order[]="+encodeURIComponent(e.getAttribute("data-id")))}));const r="hashtoken="+encodeURIComponent(this.token)+"&id_hook="+o+"&"+n.join("&");this.sendRequest("index.php?controller=layout&action=sort",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:r})}})}))}initDeletion(){document.querySelectorAll(".btn-delete-item").forEach((e=>{e.addEventListener("click",(t=>{this.currentDeleteId=e.getAttribute("data-id"),this.deleteModal&&this.deleteModal.show()}))}));const e=document.getElementById("confirmDeleteAction");e&&e.addEventListener("click",(()=>{if(this.currentDeleteId){const e="index.php?controller=layout&action=delete&id="+this.currentDeleteId+"&hashtoken="+encodeURIComponent(this.token);this.sendRequest(e,{method:"GET"}),this.deleteModal.hide()}}))}}